    (0, 1, "AP ఎన్నవ రకాల ఖనిజాలను కలిగి ఉంది?", "42", "45", "50", "48", "d", "AP 48 రకాల ఖనిజాలను కలిగి ఉంది (2022-23 సర్వే)."),
    (0, 2, "AP ఏ ఖనిజ రాజ్యం వర్గీకరణ కోసం ప్రసిద్ధి?", "ఆభరణ ఖనిజ", "రత్నగర్భ", "సుందర ధనం", "రత్నభూమి", "b", "AP 'రత్నగర్భ' (రత్నాలతో పూర్ణ) గా వర్గీకృతమైంది."),
    (0, 2, "2024-25 సర్వేలో AP ఖనిజ రాజస్వం ఎంత (జనవరి 10 వరకు)?", "₹1,500 Cr", "₹2,031 Cr", "₹2,500 Cr", "₹1,800 Cr", "b", "2024-25 సర్వేలో FY నుండి ₹2,031 కోటి రాజస్వం (Major ₹737 Cr + Minor ₹1,294 Cr)."),
    (1, 1, "APMDC నిర్వహిత బాక్సైట్ గని ఎక్కడ?", "కడప", "కర్నూలు", "విలారు", "ప్రకాశం", "c", "APMDC బాక్సైట్ గని ద్వారకా తిరుమల (విలారు జిల్లా)లో ఉంది."),
    (1, 1, "బెరైటీస్ గని (APMDC) ఎక్కడ ఉంది?", "న్యూరు", "ప్రకాశం", "కడప", "అన్నమయ్య (మంగంపేట)", "d", "APMDC బెరైటీస్ గని మంగంపేట (అన్నమయ్య జిల్లా)లో ఉంది."),
    (1, 1, "ఆస్బెస్టాస్ గని (APMDC) ఏ జిల్లాలో?", "కర్నూలు", "కడప", "చిత్తూర్", "అనంతపూర్", "b", "APMDC ఆస్బెస్టాస్ గని కడప జిల్లాలో ఉంది."),
