    (1, 1, "సీసం (లెడ్) నిక్షేపాలు ఏ జిల్లాలో?", "శ్రీకాకుళం", "కడప", "గుంటూరు", "ప్రకాశం", "b", "సీసం నిక్షేపాలు కడప జిల్లాలో GSI నిక్షేపాలు."),
    (1, 2, "సున్నపురాయి (లైమ్‌స్టోన్) నిక్షేపాలు ఏక్కడ?", "కర్నూలు, గుంటూరు", "తూర్పుగోదావరి", "ప్రకాశం", "కడప", "a", "సున్నపురాయి GSI నిక్షేపాలు కర్నూలు, గుంటూరు జిల్లాలలో."),
    (1, 2, "మాంగనీస్ నిక్షేపాలు ఏ జిల్లాలలో GSI?", "శ్రీకాకుళం, విజయనగరం, విశాఖపట్నం", "కర్నూలు", "చిత్తూర్", "కడప", "a", "మాంగనీస్ నిక్షేపాలు శ్రీకాకుళం, విజయనగరం, విశాఖపట్నం జిల్లాలలో."),
    (1, 2, "బంగారం (గోల్డ్) GSI నిక్షేపాలు ఏక్కడ?", "తూర్పుగోదావరి", "ప్రకాశం", "అనంతపూర్, కడప, కర్నూలు, చిత్తూర్", "గుంటూరు", "c", "బంగారం నిక్షేపాలు అనంతపూర్, కడప, కర్నూలు, చిత్తూర్‌లో GSI."),
    (2, 1, "కాజార్ (కాओలిన్) ఖనిజం ఎక్కడ ఉత్పత్తి?", "అగ్గిగుండాల, బొందలమొట్టు", "కడప", "కర్నూలు", "బొందలమొట్టు", "a", "కాజార్ ఉత్పత్తి అగ్గిగుండాల, బొందలమొట్టు (పల్నాడు), జంగంరాజపల్లి (కడప)లో."),
    (2, 1, "సీసం ఖనిజం నెల్లూరు ఏ ప్రాంతంలో?", "మర్రిపాడు", "కారంపూడి", "కొయలకుంట్ల", "జంగంరాజు పల్లి", "c", "సీసం నిక్షేపాలు కొయలకుంట్ల (నంద్యాల), జంగంరాజు పల్లి (కడప), కారంపూడి."),
    (2, 1, "డాలమైట్ మైనింగ్ ఎక్కడ?", "ఇవేవీ", "ఆ", "ఈ", "చింతపల్లి, దోమకొండలు", "d", "డాలమైట్ చింతపల్లి (అల్లూరి), దోమకొండలు (తూర్పుగోదావరి)లో."),
    (2, 1, "మాంగనీస్ ఖనిజం ఏ ప్రాంతంలో ఉత్పత్తి?", "తూర్పుగోదావరి", "కర్నూలు", "ప్రకాశం", "కొడూరు, గరివిడి", "d", "మాంగనీస్ కొడూరు (శ్రీకాకుళం), గరివిడి (విజయనగరం)లో."),
