    (3, 1, "బెరైటీస్ ఖనిజ ఉత్పత్తి ఎక్కడ?", "చిత్తూర్", "కడప", "అన్నమయ్య (మంగంపేట)", "నెల్లూరు", "c", "బెరైటీస్ అన్నమయ్య (మంగంపేట) నిక్షేపాలు, నెల్లూరు."),
    (3, 1, "ఆస్బెస్టాస్ ఉత్పత్తి జిల్లా ఏది?", "అనంతపూర్", "కర్నూలు", "కడప", "చిత్తూర్", "c", "ఆస్బెస్టాస్ కడప (చిన్నకుడాలు, పూలివెందులు, బ్రాహ్మణపల్లి)."),
    (3, 1, "క్రూడ్ ఆయిల్ (చమురు) ఏ జిల్లాలో?", "తూర్పుగోదావరి", "కర్నూలు", "కడప", "ప్రకాశం", "a", "క్రూడ్ ఆయిల్ తూర్పుగోదావరి (K.G. బేసిన్) నిక్షేపాలు."),
    (3, 1, "డోలమైట్ ఉత్పత్తి జిల్లాలు?", "కడప", "ప్రకాశం", "కర్నూలు, అనంతపూర్, కడప", "చిత్తూర్", "c", "డోలమైట్ కర్నూలు, అనంతపూర్, కడప నిక్షేపాలు."),
    (3, 1, "మాంగనీస్ ఉత్పత్తి జిల్లాలు?", "కడప", "చిత్తూర్", "కర్నూలు", "శ్రీకాకుళం, విజయనగరం", "d", "మాంగనీస్ శ్రీకాకుళం, విజయనగరం నిక్షేపాలు."),
    (3, 2, "సీసం (లెడ్) ఉత్పత్తి జిల్లాలు?", "అనంతపూర్", "చిత్తూర్", "నంద్యాల, గుంటూరు, కడప", "ప్రకాశం", "c", "సీసం నంద్యాల (కొయలకుంట్ల), గుంటూరు (కారంపూడి), కడప."),
    (3, 2, "రాగి (కాపర్) ఉత్పత్తి జిల్లాలు?", "పల్నాడు, కడప", "చిత్తూర్", "కర్నూలు", "ప్రకాశం", "a", "రాగి కల్నాడు (అగ్గిగుండాల), బొందలమొట్టు కడప."),
